1	<!DOCTYPE html>
2	<html lang="ja">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>締め付けトルク判断支援ツール — JIS B 1083準拠</title>
7	<style>
8	*{box-sizing:border-box;margin:0;padding:0}
9	html,body{width:100%;overflow-x:hidden}
10	.app{display:flex;flex-direction:row;width:100%;min-height:800px;font-family:sans-serif;font-size:13px;color:#222;overflow:hidden}
11	.sb{width:290px;min-width:290px;max-width:290px;background:#fff;border-right:0.5px solid #ddd;display:flex;flex-direction:column;height:800px}
12	.sb-hd{padding:10px 13px 8px;border-bottom:0.5px solid #ddd;flex-shrink:0}
13	.sb-title{font-size:13px;font-weight:500}
14	.sb-sub{font-size:10px;color:#888;margin-top:1px}
15	.sb-body{padding:9px 13px;flex:1;overflow-y:auto}
16	.sb-ft{padding:8px 13px;border-top:0.5px solid #ddd;display:flex;flex-direction:column;gap:4px;flex-shrink:0}
17	.sec{margin-bottom:10px}
18	.sec-h{font-size:10px;font-weight:500;color:#999;letter-spacing:0.07em;text-transform:uppercase;margin-bottom:5px;padding-bottom:3px;border-bottom:0.5px solid #eee}
19	.sec-h.blue{color:#185FA5;border-color:#B5D4F4}
20	.sec-h.coral{color:#993C1D;border-color:#F5C4B3}
21	.sec-h.teal{color:#0F6E56;border-color:#9FE1CB}
22	.f{margin-bottom:5px}
23	.f label{display:block;font-size:11px;color:#666;margin-bottom:2px}
24	.f select,.f input[type=number]{width:100%;padding:4px 6px;border:0.5px solid #ccc;border-radius:6px;background:#f7f7f7;color:#222;font-size:11px}
25	.f2{display:grid;grid-template-columns:1fr 1fr;gap:5px}
26	.f input[type=range]{width:100%;margin:2px 0 1px}
27	.rrow{display:flex;justify-content:space-between;font-size:10px;color:#aaa}
28	.rval{font-weight:500;color:#222}
29	.info-pill{display:inline-block;padding:2px 6px;border-radius:4px;font-size:10px;background:#f2f2f2;color:#666;border:0.5px solid #ddd;margin-top:2px}
30	.btn{padding:5px 10px;border:0.5px solid #ccc;border-radius:6px;background:#fff;color:#222;font-size:11px;cursor:pointer;width:100%}
31	.btn:hover{background:#f2f2f2}
32	.btn-p{background:#185FA5;color:#fff;border-color:#185FA5}
33	.btn-p:hover{background:#0C447C}
34	.main{flex:1;min-width:0;display:flex;flex-direction:column;background:#f5f5f3;height:800px}
35	.topbar{display:flex;align-items:center;gap:6px;padding:8px 12px;background:#fff;border-bottom:0.5px solid #ddd;flex-wrap:wrap;flex-shrink:0}
36	.topbar-t{font-size:13px;font-weight:500}
37	.badge{display:inline-flex;align-items:center;padding:2px 7px;border-radius:10px;font-size:10px;font-weight:500}
38	.b-bl{background:#E6F1FB;color:#0C447C}
39	.b-rd{background:#FCEBEB;color:#791F1F}
40	.b-gn{background:#EAF3DE;color:#27500A}
41	.b-am{background:#FAEEDA;color:#633806}
42	.sp{flex:1}
43	.tabs{display:flex;gap:2px}
44	.tab{padding:4px 10px;font-size:11px;cursor:pointer;border:0.5px solid transparent;border-radius:6px;color:#888}
45	.tab.on{background:#fff;border-color:#ccc;color:#222;font-weight:500}
46	.content{flex:1;padding:10px 12px;overflow-y:auto;min-width:0;width:100%}
47	.mrow{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:5px;margin-bottom:8px}
48	.mc{background:#fff;border:0.5px solid #e0e0e0;border-radius:8px;padding:7px 9px}
49	.mc-l{font-size:10px;color:#888;margin-bottom:2px}
50	.mc-v{font-size:15px;font-weight:500;line-height:1.1}
51	.mc-u{font-size:10px;color:#888;margin-left:1px}
52	.mc-s{font-size:10px;color:#aaa;margin-top:2px}
53	.mc.ok .mc-v{color:#3B6D11}.mc.info .mc-v{color:#185FA5}
54	.mc.warn .mc-v{color:#854F0B}.mc.danger .mc-v{color:#A32D2D}
55	.alert{padding:6px 10px;border-radius:6px;font-size:11px;margin-bottom:7px;border-left:3px solid}
56	.al-ok{background:#EAF3DE;color:#27500A;border-color:#639922}
57	.al-dn{background:#FCEBEB;color:#791F1F;border-color:#E24B4A}
58	.al-wn{background:#FAEEDA;color:#633806;border-color:#EF9F27}
59	.chart-wrap{width:100%;min-width:0;overflow:hidden}
60	.cg{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:7px;width:100%;min-width:0}
61	.cc{background:#fff;border:0.5px solid #e0e0e0;border-radius:8px;padding:9px 11px;min-width:0;overflow:hidden}
62	.cc.full{grid-column:1/-1}
63	.cc-t{font-size:10px;font-weight:500;color:#888;margin-bottom:5px}
64	.leg{display:flex;gap:8px;flex-wrap:wrap;margin-top:5px}
65	.li{display:flex;align-items:center;gap:3px;font-size:10px;color:#888}
66	.ls{width:12px;height:2px;border-radius:1px;flex-shrink:0}
67	.tcard{background:#fff;border:0.5px solid #e0e0e0;border-radius:8px;overflow:hidden;margin-bottom:7px}
68	.th2{padding:6px 10px;border-bottom:0.5px solid #e0e0e0;font-size:11px;font-weight:500;display:flex;align-items:center;gap:6px}
69	table.dt{width:100%;font-size:11px;border-collapse:collapse}
70	table.dt th{padding:3px 8px;background:#f7f7f7;color:#888;font-weight:500;text-align:right;border-bottom:0.5px solid #e0e0e0;white-space:nowrap;font-size:10px}
71	table.dt th:first-child{text-align:left}
72	table.dt td{padding:3px 8px;text-align:right;border-bottom:0.5px solid #e0e0e0;font-variant-numeric:tabular-nums}
73	table.dt td:first-child{text-align:left;color:#888}
74	table.dt tr.pl td{background:#FAEEDA14}
75	table.dt tr.lm td{background:#FCEBEB20;color:#A32D2D}
76	.sb2{display:inline-block;padding:1px 5px;border-radius:9px;font-size:9px}
77	.s-e{background:#E6F1FB;color:#0C447C}.s-p{background:#FAEEDA;color:#633806}.s-l{background:#FCEBEB;color:#791F1F}
78	.stiff-row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;text-align:center;background:#f7f7f7;border-radius:8px;padding:9px;margin-bottom:8px}
79	.stiff-v{font-size:14px;font-weight:500}
80	.stiff-l{font-size:10px;color:#888;margin-top:2px}
81	</style>
82	</head>
83	<body>
84	<div class="app">
85	  <div class="sb">
86	    <div class="sb-hd">
87	      <div class="sb-title">締め付けトルク解析</div>
88	      <div class="sb-sub">JIS B 1083 / Alexander式 準拠</div>
89	    </div>
90	    <div class="sb-body">
91	      <div class="sec">
92	        <div class="sec-h blue">ボルト仕様</div>
93	        <div class="f"><label>ボルト径</label>
94	          <select id="diam" onchange="calc()">
95	            <option value="3">M3</option><option value="4">M4</option><option value="5">M5</option>
96	            <option value="6" selected>M6</option><option value="8">M8</option><option value="10">M10</option>
97	            <option value="12">M12</option><option value="16">M16</option><option value="20">M20</option>
98	          </select>
99	        </div>
100	        <div class="f"><label>強度区分</label>
101	          <select id="grade" onchange="onGradeChange()">
102	            <option value="4.6">4.6（Sy=240 / Su=400 MPa）</option>
103	            <option value="4.8">4.8（Sy=340 / Su=420 MPa）</option>
104	            <option value="8.8">8.8（Sy=660 / Su=830 MPa）</option>
105	            <option value="10.9" selected>10.9（Sy=940 / Su=1040 MPa）</option>
106	            <option value="12.9">12.9（Sy=1100 / Su=1220 MPa）</option>
107	          </select>
108	        </div>
109	        <div class="f">
110	          <label>参考特性（強度区分より自動設定）</label>
111	          <div id="bolt-info" class="info-pill">合金鋼（焼入れ焼戻し）/ E = 206 GPa</div>
112	        </div>
113	        <div class="f"><label>ボルト有効長さ Lg (mm)</label>
114	          <input type="number" id="bolt_lg" value="20" min="1" max="200" onchange="calc()">
115	        </div>
116	        <div class="f2">
117	          <div class="f"><label>μₜ（ねじ面）: <span class="rval" id="mu_t_v">0.13</span></label>
118	            <input type="range" id="mu_t" min="0.05" max="0.30" step="0.01" value="0.13" oninput="ge('mu_t_v').textContent=parseFloat(this.value).toFixed(2);calc()">
119	          </div>
120	          <div class="f"><label>μw（座面）: <span class="rval" id="mu_w_v">0.13</span></label>
121	            <input type="range" id="mu_w" min="0.05" max="0.30" step="0.01" value="0.13" oninput="ge('mu_w_v').textContent=parseFloat(this.value).toFixed(2);calc()">
122	          </div>
123	        </div>
124	        <div class="f"><label>ねじ山角度</label>
125	          <select id="thread_angle" onchange="calc()">
126	            <option value="60" selected>60° — メートルねじ（JIS）</option>
127	            <option value="55">55° — ウィットねじ</option>
128	          </select>
129	        </div>
130	        <div class="f"><label>ワッシャー</label>
131	          <select id="washer" onchange="calc()">
132	            <option value="none" selected>なし</option>
133	            <option value="flat">平ワッシャー（座面×1.5）</option>
134	            <option value="spring">スプリングワッシャー（μw×0.9）</option>
135	          </select>
136	        </div>
137	      </div>
138	      <div class="sec">
139	        <div class="sec-h coral">相手材（めねじ側）</div>
140	        <div class="f"><label>材質</label>
141	          <select id="nut_mat" onchange="calc()">
142	            <option value="aluminum" selected>アルミニウム合金（A6061）</option>
143	            <option value="a5052">アルミニウム合金（A5052）</option>
144	            <option value="steel">鋼（SS400）</option>
145	            <option value="s45c">鋼（S45C）</option>
146	            <option value="cast_iron">鋳鉄（FC200）</option>
147	            <option value="titanium">チタン合金（Ti-6Al-4V）</option>
148	            <option value="brass">真鍮（C3604）</option>
149	            <option value="resin">エンジニアリングプラスチック</option>
150	          </select>

350	          <div class="th2">破損解析詳細</div>
351	          <table class="dt"><thead><tr>
352	            <th>破損モード</th><th>限界軸力(kN)</th><th>限界T(Nm)</th><th>余裕度</th><th>支配的</th>
353	          </tr></thead><tbody id="bd-tbl"></tbody></table>
354	        </div>
355	      </div>
356	
357	      <div id="pane-joint" style="display:none">
358	        <div class="stiff-row">
359	          <div><div class="stiff-v" id="jt-kb">—</div><div class="stiff-l">ボルト剛性 kb (N/mm)</div></div>
360	          <div><div class="stiff-v" id="jt-kc">—</div><div class="stiff-l">部材剛性 kc (N/mm)</div></div>
361	          <div><div class="stiff-v" id="jt-phi">—</div><div class="stiff-l">剛性比 Φ = kb/(kb+kc)</div></div>
362	        </div>
363	        <div class="cg">
364	          <div class="cc">
365	            <div class="cc-t">外部軸力による軸力変動</div>
366	            <div class="chart-wrap" style="position:relative;height:190px">
367	              <canvas id="cJT" role="img" aria-label="軸力変動グラフ">軸力変動</canvas>
368	            </div>
369	          </div>
370	          <div class="cc">
371	            <div class="cc-t">剛性比 Φ の影響（外力応答特性）</div>
372	            <div class="chart-wrap" style="position:relative;height:190px">
373	              <canvas id="cPH" role="img" aria-label="剛性比グラフ">剛性比グラフ</canvas>
374	            </div>
375	          </div>
376	        </div>
377	        <div class="tcard">
378	          <div class="th2">継手解析 結果サマリ</div>
379	          <table class="dt"><thead><tr><th>項目</th><th>値</th><th>備考</th></tr></thead>
380	          <tbody id="jt-tbl"></tbody></table>
381	        </div>
382	      </div>
383	    </div>
384	  </div>
385	</div>
386	
387	<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js"></script>
388	<script src="https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js"></script>
389	<script>
390	const BOLT={3:{p:0.5,d2:2.675,d3:2.459,As:5.03,dw:5.5,dh:3.4},4:{p:0.7,d2:3.545,d3:3.242,As:8.78,dw:7.0,dh:4.5},5:{p:0.8,d2:4.480,d3:4.134,As:14.2,dw:8.8,dh:5.5},6:{p:1.0,d2:5.350,d3:4.917,As:20.1,dw:10.0,dh:6.6},8:{p:1.25,d2:7.188,d3:6.647,As:36.6,dw:13.0,dh:9.0},10:{p:1.5,d2:9.026,d3:8.376,As:58.0,dw:16.0,dh:11.0},12:{p:1.75,d2:10.863,d3:10.106,As:84.3,dw:18.0,dh:13.5},16:{p:2.0,d2:14.701,d3:13.835,As:157,dw:24.0,dh:17.5},20:{p:2.5,d2:18.376,d3:17.294,As:245,dw:30.0,dh:22.0}};
391	const GRADE={'4.6':{Sy:240,Su:400,E:206,matNote:'低炭素鋼'},'4.8':{Sy:340,Su:420,E:206,matNote:'低炭素鋼'},'8.8':{Sy:660,Su:830,E:206,matNote:'中炭素鋼（焼入れ焼戻し）'},'10.9':{Sy:940,Su:1040,E:206,matNote:'合金鋼（焼入れ焼戻し）'},'12.9':{Sy:1100,Su:1220,E:206,matNote:'合金鋼（焼入れ焼戻し）'}};
392	const NUT_MAT={aluminum:{tau:80,bearing:60,name:'アルミ A6061',E:70},a5052:{tau:70,bearing:50,name:'アルミ A5052',E:70},steel:{tau:320,bearing:300,name:'鋼 SS400',E:206},s45c:{tau:420,bearing:380,name:'鋼 S45C',E:206},cast_iron:{tau:150,bearing:120,name:'鋳鉄 FC200',E:100},titanium:{tau:450,bearing:350,name:'チタン合金',E:114},brass:{tau:120,bearing:100,name:'真鍮 C3604',E:103},resin:{tau:40,bearing:30,name:'エンプラ',E:3}};
393	const CL_MAT={aluminum:{E:70,name:'アルミ合金',bearing:60},steel:{E:206,name:'鋼',bearing:300},cast_iron:{E:100,name:'鋳鉄',bearing:120},titanium:{E:114,name:'チタン合金',bearing:350},brass:{E:103,name:'真鍮',bearing:100},resin:{E:3,name:'エンプラ',bearing:30},cfrp:{E:70,name:'CFRP',bearing:150}};
394	const CH={};let RES=null,RES2=null,curTab='graph';
395	function ge(id){return document.getElementById(id)}
396	function gv(id){return ge(id).value}
397	function onGradeChange(){const gr=GRADE[gv('grade')];ge('bolt-info').textContent=`${gr.matNote} / E = ${gr.E} GPa`;calc()}
398	function onClampedMatChange(ab){const m=CL_MAT[gv('clamped_mat_'+ab)];ge('bearing_'+ab).value=m.bearing;calc()}
399	function calcStiff(b,Eb,Lg,mA,mB,tA,tB){const kb=Eb*1000*b.As/Lg,Ac=(Math.PI/4)*(b.dw*b.dw-b.dh*b.dh),kca=CL_MAT[mA].E*1000*Ac/tA,kcb=CL_MAT[mB].E*1000*Ac/tB,kc=1/(1/kca+1/kcb);return{kb,kc,kca,kcb,phi:kb/(kb+kc)}}
400	function doCalc(d,grK,Lg,mt,mw,nutK,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns){
401	  const b=BOLT[d],gr=GRADE[grK],nut=NUT_MAT[nutK],Eb=gr.E;
402	  const half=ang/2*Math.PI/180,beta=Math.atan(b.p/(Math.PI*b.d2)),rho=Math.atan(mt/Math.cos(half));
403	  let dw=b.dw,muw=mw;
404	  if(was==='flat')dw*=1.5;if(was==='spring')muw*=0.9;
405	  const bArea=(Math.PI/4)*(dw*dw-b.dh*b.dh),le=dep*d,nTh=le/b.p;
406	  const Fbrk=gr.Su*b.As/1000*tmp,Fstr=nut.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000,FbA=bA*bArea/1000,FbB=bB*bArea/1000,Fyld=gr.Sy*b.As/1000*tmp;
407	  const Flim=Math.min(Fbrk,Fstr,FbA,FbB);
408	  const failMode=[{mode:'ボルト破断',F:Fbrk},{mode:'山飛び（めねじ）',F:Fstr},{mode:'座面陥没 A面',F:FbA},{mode:'座面陥没 B面',F:FbB}].reduce((a,x)=>x.F<a.F?x:a).mode;
409	  const denom=(b.d2/2)*Math.tan(beta+rho)+(dw/2)*muw,Test=Flim*denom*1.35,step=Test/ns;
410	  const rows=[];
411	  for(let i=0;i<=ns+30;i++){
412	    const T=i*step,Fe=T/denom,sig=Fe*1000/b.As,J=Math.PI*Math.pow(b.d3/2,4)/2,tau=T*1000*(b.d3/2)/J*0.5,seq=Math.sqrt(sig*sig+3*tau*tau),plastic=seq>gr.Sy*tmp,Fact=plastic?Math.min(Fe,Fyld*1.01):Fe,util=seq/(gr.Su*tmp)*100;
413	    rows.push({T:+T.toFixed(3),F:+(Fact/1000).toFixed(4),sig:+sig.toFixed(1),tau:+tau.toFixed(1),seq:+seq.toFixed(1),util:+util.toFixed(1),plastic,over:Fact/1000>=Flim/1000*0.998});
414	    if(Fact/1000>Flim/1000*1.02)break;
415	  }
416	  return{rows,Flim,Fbrk,Fstr,FbA,FbB,Fyld,T_lim:rows.find(r=>r.over)?.T||null,T_yld:rows.find(r=>r.plastic)?.T||null,failMode,b,gr,nut,nutK,grK,d,dep,mu_t:mt,mu_w:muw,denom,dw,stiff:calcStiff(b,Eb,Lg,cmA,cmB,tA,tB),Eb,Lg,cmA,cmB,tA,tB,bA,bB};
417	}
418	function calc(){
419	  const ns=200,d=+gv('diam'),gr=gv('grade'),Lg=+gv('bolt_lg'),mt=+gv('mu_t'),mw=+gv('mu_w'),nut=gv('nut_mat'),dep=+gv('depth'),ang=+gv('thread_angle'),was=gv('washer'),tmp=+gv('temp'),bA=+gv('bearing_a'),bB=+gv('bearing_b'),cmA=gv('clamped_mat_a'),cmB=gv('clamped_mat_b'),tA=+gv('thick_a'),tB=+gv('thick_b');
420	  RES=doCalc(d,gr,Lg,mt,mw,nut,dep,ang,was,tmp,bA,bB,cmA,cmB,tA,tB,ns);
421	  const cmp=ge('cmp_on').checked;
422	  RES2=cmp?doCalc(+gv('diam2'),gv('grade2'),Lg,0.13,0.13,gv('nut_mat2'),+gv('depth2'),60,'none',tmp,bA,bB,gv('clamped_mat_a2'),gv('clamped_mat_b2'),+gv('thick_a2'),+gv('thick_b2'),ns):null;
423	  const sf=+gv('safety'),fext=+gv('f_ext');
424	  updateTop(RES,sf,cmp);
425	  if(curTab==='graph')drawGraphs(RES,RES2,sf);
426	  else if(curTab==='table')buildTable(RES);
427	  else if(curTab==='breakdown')buildBreakdown(RES,sf);
428	  else buildJoint(RES,sf,fext);
429	}
430	function updateTop(r,sf,cmp){
431	  ge('v-flim').innerHTML=(r.Flim/1000).toFixed(2)+'<span class="mc-u">kN</span>';
432	  ge('v-tlim').innerHTML=(r.T_lim?r.T_lim.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
433	  ge('v-tyld').innerHTML=(r.T_yld?r.T_yld.toFixed(1):'—')+'<span class="mc-u">Nm</span>';
434	  ge('v-trec').innerHTML=(r.T_lim?(r.T_lim/sf).toFixed(1):'—')+'<span class="mc-u">Nm</span>';
435	  ge('v-trec-s').textContent='安全率 '+sf.toFixed(1);
436	  ge('v-phi').innerHTML=r.stiff.phi.toFixed(3);
437	  ge('mc0').className='mc '+(r.failMode!=='ボルト破断'?'danger':'ok');
438	  ge('bdg-mode').textContent=cmp?'比較モード':'単一解析';ge('bdg-mode').className='badge '+(cmp?'b-am':'b-bl');
439	  ge('bdg-fail').textContent=r.failMode==='ボルト破断'?'正常':'警告: '+r.failMode;ge('bdg-fail').className='badge '+(r.failMode==='ボルト破断'?'b-gn':'b-rd');
440	  const alerts=[];
441	  if(r.failMode==='山飛び（めねじ）')alerts.push('<div class="alert al-dn"><strong>警告: 山飛びリスク</strong>　めねじせん断破壊がボルト破断より先に発生します。ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。</div>');
