  else if(r.failMode.includes('座面')){alertText=`警告: 座面陥没リスク（${r.failMode}）— ワッシャー使用または許容面圧を見直してください。`;alertStyle='background:#FCEBEB;color:#791F1F;border-left:3px solid #E24B4A';}
  const failModes=[{name:'ボルト破断',F:r.Fbrk},{name:'山飛び（めねじ）',F:r.Fstr},{name:'座面陥没 A面',F:r.FbA},{name:'座面陥没 B面',F:r.FbB}];
  const sec=(title)=>`<div style="font-size:12px;font-weight:bold;color:#185FA5;border-left:3px solid #185FA5;padding-left:8px;margin:14px 0 7px">${title}</div>`;
  const trow=(cells,bg)=>`<tr style="background:${bg||'transparent'}">${cells.map((c,i)=>`<td style="padding:4px 8px;border-bottom:0.5px solid #e0e0e0;${i>0?'text-align:right':''}${i===0?';color:#888':''}${c.s||''}">${c.v!==undefined?c.v:c}</td>`).join('')}</tr>`;
  const resultCards=[
    {l:'限界軸力',v:(r.Flim/1000).toFixed(2),u:'kN'},{l:'限界トルク',v:r.T_lim?r.T_lim.toFixed(1):'—',u:'Nm'},
    {l:'降伏トルク',v:r.T_yld?r.T_yld.toFixed(1):'—',u:'Nm'},{l:'推奨トルク',v:r.T_lim?(r.T_lim/sf).toFixed(1):'—',u:`Nm / S=${sf.toFixed(1)}`},
    {l:'剛性比 Φ',v:s.phi.toFixed(4),u:''},{l:'支配的破損',v:r.failMode,u:''}
  ];
  const cardCell=(c)=>`<td style="width:33%;padding:3px"><div style="background:#f5f5f3;border-radius:6px;padding:7px 9px"><div style="font-size:9px;color:#888;margin-bottom:2px">${c.l}</div><div style="font-size:13px;font-weight:500">${c.v}<span style="font-size:9px;color:#888;margin-left:2px">${c.u}</span></div></div></td>`;
  const html=`<div style="font-family:sans-serif;font-size:11px;color:#222;padding:24px 28px;width:680px">
  <div style="border-bottom:2px solid #185FA5;padding-bottom:8px;margin-bottom:4px">
    <div style="font-size:17px;font-weight:bold;color:#185FA5">締め付けトルク解析レポート</div>
    <div style="font-size:9px;color:#888;margin-top:3px">JIS B 1083 / Alexander式 準拠 &nbsp;|&nbsp; 生成日時: ${dateStr}</div>
  </div>
  ${sec('解析条件')}
  <table style="width:100%;border-collapse:collapse;font-size:10px">
    ${trow([{v:'ボルト径 / 強度区分'},{v:`M${r.d} / ${r.grK} &nbsp;(Sy=${r.gr.Sy} MPa, Su=${r.gr.Su} MPa)`}],'#f7f7f7')}
    ${trow([{v:'有効長さ Lg'},{v:`${r.Lg} mm`}])}
    ${trow([{v:'摩擦係数 μt / μw'},{v:`${r.mu_t.toFixed(2)} / ${r.mu_w.toFixed(2)}`}],'#f7f7f7')}
    ${trow([{v:'めねじ材 / ねじ込み深さ'},{v:`${r.nut.name} / ${r.dep}D`}])}
    ${trow([{v:'被締結材 A'},{v:`${CL_MAT[r.cmA].name}, t=${r.tA} mm, 許容面圧 ${r.bA} MPa`}],'#f7f7f7')}
