    ${trow([{v:'安全率 / 外部軸力'},{v:`${sf.toFixed(1)} / ${fext} N`}],'#f7f7f7')}
  </table>
  ${sec('解析結果サマリ')}
  <table style="width:100%;border-collapse:collapse;margin-bottom:7px">
    <tr>${resultCards.slice(0,3).map(cardCell).join('')}</tr>
    <tr>${resultCards.slice(3,6).map(cardCell).join('')}</tr>
  </table>
  <div style="padding:6px 10px;border-radius:6px;font-size:10px;${alertStyle}">${alertText}</div>
  ${sec('T-F線図 / 等価応力推移')}
  <table style="width:100%;border-collapse:collapse"><tr>
    <td style="width:60%;padding-right:5px">${tfImg?`<img src="${tfImg}" style="width:100%;border:0.5px solid #e0e0e0;border-radius:6px">`:''}</td>
    <td style="width:40%;padding-left:5px">${stImg?`<img src="${stImg}" style="width:100%;border:0.5px solid #e0e0e0;border-radius:6px">`:''}</td>
