  ${sec('継手剛性解析')}
  <table style="width:100%;border-collapse:collapse;font-size:10px">
    ${[
      ['ボルト剛性 kb',`${(s.kb/1000).toFixed(0)} kN/mm`,`E=${r.Eb} GPa, As=${r.b.As} mm², Lg=${r.Lg} mm`],
      ['部材合成剛性 kc',`${(s.kc/1000).toFixed(0)} kN/mm`,'1/(1/kca + 1/kcb)'],
      ['剛性比 Φ',s.phi.toFixed(4),'Φ < 0.1 が推奨'],
      ['初期締付力 Fi',`${(Fi/1000).toFixed(2)} kN`,`推奨T: ${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm 締付時`],
      ['外部軸力によるΔFb',`${(s.phi*(fext||0)/1000).toFixed(2)} kN`,`Fext = ${fext} N`],
      ['残留締付力',`${Math.max(0,(Fi-(1-s.phi)*(fext||0))/1000).toFixed(2)} kN`,'0以上を確認（開口防止）']
    ].map(([a,b,c],i)=>trow([{v:a},{v:b},{v:c,s:';color:#888;text-align:right'}],i%2===0?'#f7f7f7':'transparent')).join('')}
  </table>
  <div style="font-size:9px;color:#aaa;text-align:center;border-top:0.5px solid #e0e0e0;padding-top:8px;margin-top:20px">
    締め付けトルク判断支援ツール — JIS B 1083準拠 &nbsp;|&nbsp; 本レポートは参考値です。重要な用途では有資格エンジニアによる検証を行ってください。
  </div>
</div>`;
  const el=document.createElement('div');
  el.innerHTML=html;
  el.style.cssText='position:fixed;left:-9999px;top:0;z-index:-1';
  document.body.appendChild(el);
  html2pdf().set({
    margin:[8,8,8,8],
    filename:`bolt_M${r.d}_${r.grK}_report.pdf`,
    image:{type:'jpeg',quality:0.97},
    html2canvas:{scale:2,useCORS:true,logging:false},
    jsPDF:{unit:'mm',format:'a4',orientation:'portrait'}
  }).from(el.firstChild).save().then(()=>document.body.removeChild(el));
}
window.addEventListener('load',()=>{onGradeChange()});

