    ${failModes.map((fm,i)=>{const isCtrl=Math.abs(fm.F-r.Flim)<0.01,mg=(fm.F/1000)/(r.Flim/1000/sf),mc=mg<1.2?'#A32D2D':mg<1.5?'#854F0B':'#3B6D11';return `<tr style="background:${i%2===0?'#fff':'#fafafa'}"><td style="padding:4px 8px;border-bottom:0.5px solid #e0e0e0;${isCtrl?'color:#A32D2D;font-weight:500':''}">${fm.name}</td><td style="padding:4px 8px;text-align:right;border-bottom:0.5px solid #e0e0e0;${isCtrl?'color:#A32D2D;font-weight:500':''}">${(fm.F/1000).toFixed(2)}</td><td style="padding:4px 8px;text-align:right;border-bottom:0.5px solid #e0e0e0;color:${mc};font-weight:500">${mg.toFixed(2)}x</td><td style="padding:4px 8px;text-align:center;border-bottom:0.5px solid #e0e0e0">${isCtrl?'★':''}</td></tr>`;}).join('')}
  </table>
