function exportPDF(){
  if(!RES||typeof html2pdf==='undefined')return;
  const r=RES,sf=+gv('safety'),fext=+gv('f_ext'),s=r.stiff;
  const Fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf;
  const tfImg=ge('cTF')?ge('cTF').toDataURL('image/png'):null;
  const stImg=ge('cST')?ge('cST').toDataURL('image/png'):null;
  const bkImg=ge('cBK')?ge('cBK').toDataURL('image/png'):null;
  const now=new Date();
  const dateStr=`${now.getFullYear()}/${String(now.getMonth()+1).padStart(2,'0')}/${String(now.getDate()).padStart(2,'0')} ${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
  let alertText='設計は良好です。ボルト破断が支配的で延性破壊が先行します。';
  let alertStyle='background:#EAF3DE;color:#27500A;border-left:3px solid #639922';
  if(r.failMode==='山飛び（めねじ）'){alertText='警告: 山飛びリスク — ねじ込み深さを 1.5D 以上に増やすか相手材を強化してください。';alertStyle='background:#FCEBEB;color:#791F1F;border-left:3px solid #E24B4A';}
  else if(r.failMode.includes('座面')){alertText=`警告: 座面陥没リスク（${r.failMode}）— ワッシャー使用または許容面圧を見直してください。`;alertStyle='background:#FCEBEB;color:#791F1F;border-left:3px solid #E24B4A';}
  const failModes=[{name:'ボルト破断',F:r.Fbrk},{name:'山飛び（めねじ）',F:r.Fstr},{name:'座面陥没 A面',F:r.FbA},{name:'座面陥没 B面',F:r.FbB}];
  const sec=(title)=>`<div style="font-size:12px;font-weight:bold;color:#185FA5;border-left:3px solid #185FA5;padding-left:8px;margin:14px 0 7px">${title}</div>`;
  const trow=(cells,bg)=>`<tr style="background:${bg||'transparent'}">${cells.map((c,i)=>`<td style="padding:4px 8px;border-bottom:0.5px solid #e0e0e0;${i>0?'text-align:right':''}${i===0?';color:#888':''}${c.s||''}">${c.v!==undefined?c.v:c}</td>`).join('')}</tr>`;
  const resultCards=[
    {l:'限界軸力',v:(r.Flim/1000).toFixed(2),u:'kN'},{l:'限界トルク',v:r.T_lim?r.T_lim.toFixed(1):'—',u:'Nm'},
    {l:'降伏トルク',v:r.T_yld?r.T_yld.toFixed(1):'—',u:'Nm'},{l:'推奨トルク',v:r.T_lim?(r.T_lim/sf).toFixed(1):'—',u:`Nm / S=${sf.toFixed(1)}`},
    {l:'剛性比 Φ',v:s.phi.toFixed(4),u:''},{l:'支配的破損',v:r.failMode,u:''}
