    </tr></table>
  </div>`:''}
  <div class="rpt-block">
    <div class="rpt-sec">破損解析</div>
    <table class="rpt-fail"><colgroup><col class="f1"><col class="f2"><col class="f3"><col class="f4"></colgroup>
      <thead><tr><th>破損モード</th><th class="num">限界軸力 (kN)</th><th class="num">余裕度</th><th class="num">支配的</th></tr></thead>
      <tbody>${fmRows.map(fm=>{
        const isCtrl=Math.abs(fm.F-r.Flim)<0.01,mg=(fm.F/1000)/(r.Flim/1000/sf);
        const mc=mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11';
        return `<tr><td class="${isCtrl?'ctrl':''}">${fm.n}</td><td class="num ${isCtrl?'ctrl':''}">${(fm.F/1000).toFixed(2)}</td><td class="num" style="${mc};font-weight:600">${mg.toFixed(2)}x</td><td class="num">${isCtrl?'★':''}</td></tr>`;
      }).join('')}</tbody>
    </table>
  </div>
