  <div class="rpt-block">
    <div class="rpt-sec">破損解析</div>
    <table class="rpt-fail"><colgroup><col class="f1"><col class="f2"><col class="f3"><col class="f4"></colgroup>
      <thead><tr><th>破損モード</th><th class="num">限界軸力 (kN)</th><th class="num">余裕度</th><th class="num">支配的</th></tr></thead>
      <tbody>${fmRows.map(fm=>{
        const isCtrl=Math.abs(fm.F-r.Flim)<0.01,mg=(fm.F/1000)/(r.Flim/1000/sf);
        const mc=mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11';
        return `<tr><td class="${isCtrl?'ctrl':''}">${fm.n}</td><td class="num ${isCtrl?'ctrl':''}">${(fm.F/1000).toFixed(2)}</td><td class="num" style="${mc};font-weight:600">${mg.toFixed(2)}x</td><td class="num">${isCtrl?'★':''}</td></tr>`;
      }).join('')}</tbody>
    </table>
  </div>
  <div class="rpt-block">
    <div class="rpt-sec">継手剛性解析</div>
    <table class="rpt-jt"><colgroup><col class="j1"><col class="j2"><col class="j3"></colgroup>
      ${[
        ['ボルト剛性 k<sub>b</sub>',`${(s.kb/1000).toFixed(0)} kN/mm`,`E = ${r.Eb} GPa, A<sub>s</sub> = ${r.b.As} mm<sup>2</sup>, L<sub>g</sub> = ${r.Lg} mm`],
        ['部材合成剛性 k<sub>c</sub>',`${(s.kc/1000).toFixed(0)} kN/mm`,'1 / (1/k<sub>ca</sub> + 1/k<sub>cb</sub>)'],
        ['剛性比 Φ',s.phi.toFixed(4),'Φ &lt; 0.1 が推奨'],
        ['初期締付力 F<sub>i</sub>',`${(Fi/1000).toFixed(2)} kN`,`推奨T: ${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm`],
        ['外部軸力による ΔF<sub>b</sub>',`${(s.phi*(fext||0)/1000).toFixed(2)} kN`,`F<sub>ext</sub> = ${fext} N`],
        ['残留締付力',`${Math.max(0,(Fi-(1-s.phi)*(fext||0))/1000).toFixed(2)} kN`,'0 以上を確認（開口防止）']
      ].map(([a,b,c])=>`<tr><td>${a}</td><td class="num">${b}</td><td class="note">${c}</td></tr>`).join('')}
    </table>
  </div>
  <div class="rpt-foot">締め付けトルク判断支援ツール — JIS B 1083準拠 &nbsp;|&nbsp; 本レポートは参考値です。重要な用途では有資格エンジニアによる検証を行ってください。</div>`;
  window.print();
  window.addEventListener('afterprint',()=>{ge('pdf-report').innerHTML='';},{once:true});
}
function applyLubePreset(v){
  if(!v)return;
  const[mt,mw]=v.split(',').map(Number);
  ge('mu_t').value=mt;ge('mu_t_v').textContent=mt.toFixed(2);
  ge('mu_w').value=mw;ge('mu_w_v').textContent=mw.toFixed(2);

